func setMtimeYear(t *testing.T, path string, year int) {
	t.Helper()
	tm := time.Date(year, 6, 1, 12, 0, 0, 0, time.UTC)
	if err := os.Chtimes(path, tm, tm); err != nil {
		t.Fatal(err)
	}
