	root := buildShareTree(t)
	// Pre-create a collision for old/a.txt.
	touch(t, filepath.Join(root, "Archive", "old", "a.txt"))

	m := newMoveManager(t, root)
	job := planAndWait(t, m, moveReq("files"))
	if job.Status != MovePlanned {
